decimal TotalPercentageSellableChicks  =0;
decimal TotalPercentageHatchPer = 0;
decimal totalReportSellableChicks = 0;
decimal totalReportSettedEggs = 0;
decimal totalFertileEggs = 0;
decimal totalSettedEggs = 0;
decimal totalFertPerc  = 0;
decimal totalHatchPerc  = 0;
decimal totalHOFFertPer  = 0;
decimal totalsellableChicks  = 0;
decimal groupSettedEggs = 0;
decimal groupSellableChicks = 0;
decimal GroupFertPer = 0;
decimal GroupFertileEggs = 0;
decimal GroupfertilityPercentage = 0;
private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal fertPer = 0;
    decimal settedEggs = 0;
    decimal sellableChicks  = 0;
    // Read fields safely
    if (GetCurrentColumnValue("FertPer") != null)
        fertPer = Convert.ToDecimal(GetCurrentColumnValue("FertPer"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));
    if (GetCurrentColumnValue("SellableChicks") != null)
        sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));


    // Calculate FertileEggs = FertPer * SettedEggs / 100
    decimal fertileEggs = (fertPer * settedEggs) / 100;


    // Sum Running totals
    totalFertPerc += fertPer ;
    totalFertileEggs += fertileEggs;
    totalSettedEggs += settedEggs;
    totalsellableChicks += sellableChicks ;
    // Get the sum values from the current group
     groupSettedEggs += settedEggs ;

     groupSellableChicks += sellableChicks ;
     GroupFertPer += fertPer  ; 

   }



private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal sellableChicks = 0;
    decimal settedEggs = 0;
    decimal fertPer = 0;

    // Read fields safely
    if (GetCurrentColumnValue("SellableChicks") != null)
        sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    if (GetCurrentColumnValue("FertPer") != null)
        fertPer = Convert.ToDecimal(GetCurrentColumnValue("FertPer"));

    // @HatchPer = SellableChicks * 100 / SettedEggs  (null-safe)
    decimal hatchPer = 0;
    if (settedEggs != 0)
        hatchPer = (sellableChicks * 100) / settedEggs;

    // Final = @HatchPer * 100 / FertPer
    if (fertPer != 0){
                TotalPercentageHatchPer = (hatchPer * 100) / fertPer;
        }


// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotalPercentageHatchPer.ToString("0.00");  // Row level %
   // accumulate total
 totalHatchPerc += hatchPer ;
 totalHOFFertPer += fertPer ;

}


private void xrTableCell30_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // --- Declare values ---
decimal sellableChicks = 0;
decimal settedEggs = 0;

// --- SellableChicks ---
if (GetCurrentColumnValue("SellableChicks") != null)
    sellableChicks = Convert.ToDecimal(GetCurrentColumnValue("SellableChicks"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    settedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Equation (row level %) ---
decimal percentage = 0;
if (settedEggs != 0)
    percentage = (sellableChicks * 100m) / settedEggs;


// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %
totalReportSellableChicks += sellableChicks;
totalReportSettedEggs += settedEggs;


}
private void xrTableCell47_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    if (totalReportSettedEggs != 0)
    TotalPercentageSellableChicks = (totalReportSellableChicks * 100m) / totalReportSettedEggs;
    ((XRTableCell)sender).Text = TotalPercentageSellableChicks.ToString("0.00");

}

private void tdCredit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    object handledEggsValue = GetCurrentColumnValue("HandledEggs");

    if (handledEggsValue == null || handledEggsValue == DBNull.Value || string.IsNullOrEmpty(handledEggsValue.ToString()))
    {
        // Set to 0 if null, DBNull, or empty
        tdCredit.Text = "0";
    }
    else
    {
        // Use the actual value
        tdCredit.Text = handledEggsValue.ToString();
    }
}





private void xrTableCell51_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal fertPerc = 0;
    decimal totalHatchPerc = 0;
    decimal finalResult = 0;
    // @FertPerc
    if (totalSettedEggs != 0)
        fertPerc = (totalFertileEggs * 100) / totalSettedEggs ;

    // @TotalHatchPerc
    if (totalSettedEggs != 0)
        totalHatchPerc = (totalsellableChicks * 100) / totalSettedEggs ;

    // FinalResult = TotalHatchPerc * 100 / FertPerc
    if (fertPerc != 0)
        finalResult = (totalHatchPerc * 100) / fertPerc;

    XRTableCell cell = (XRTableCell)sender;
    cell.Text = finalResult.ToString("N2") ;
}


private void xrTableCell49_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Final Result
    decimal finalResult = 0;

    if (totalSettedEggs != 0){
                finalResult =  (totalFertileEggs * 100m) / totalSettedEggs  ; 
        }

    // Display formatted value (2 decimals + % sign)
    XRTableCell cell = sender as XRTableCell;
    cell.Text = finalResult.ToString("N2");

}

private void xrTableCell64_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     decimal percentage = 0;

     // Calculate percentage
    if (groupSettedEggs != 0)
        percentage = groupSellableChicks * 100 / groupSettedEggs;
        // Display formatted value (2 decimals + % sign)
    XRTableCell cell = sender as XRTableCell;
    cell.Text = percentage.ToString("N2");

}

private void xrTableCell66_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     if (groupSettedEggs != 0)
    {
        // Calculate total fertile eggs
        GroupFertileEggs += GroupFertPer * groupSettedEggs / 100;

        // Calculate final percentage
        GroupfertilityPercentage = GroupFertileEggs * 100 / groupSettedEggs ;
    }

    XRTableCell cell = sender as XRTableCell;
    cell.Text = GroupfertilityPercentage.ToString("N2");
}

private void xrTableCell68_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal GroupfertPerc  = 0;
    decimal GroupHatchPerc= 0 ;
    decimal finalResult  = 0;
     // @FertPerc
    if (groupSettedEggs != 0)
        GroupfertPerc = (GroupFertileEggs * 100) / groupSettedEggs ;

    // @TotalHatchPerc
    if (groupSettedEggs != 0)
        GroupHatchPerc = (groupSellableChicks * 100) / groupSettedEggs ;

    // FinalResult = TotalHatchPerc * 100 / FertPerc
    if (GroupfertPerc != 0)
        finalResult = (GroupHatchPerc * 100) / GroupfertPerc ;    

    XRTableCell cell = sender as XRTableCell;
    cell.Text = finalResult.ToString("N2");


}
